      "content": "const { generateId } = require('../../lib/id');

let tasksStore = [];

async function getAllTasks(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function createTask(projectId, description) {
  const projectExists = tasksStore.some(task => task.projectId === projectId);
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  const newTask = { id: generateId(), projectId, description, status: 'todo' };
  tasksStore.push(newTask);
  return newTask;
}

module.exports = { getAllTasks, createTask };
