      "content": "const { generateId } = require('../../lib/id');

let commentsStore = [];

async function getAllComments(projectId, taskId) {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

async function addComment(projectId, taskId, content) {
  const taskExists = commentsStore.some(comment => comment.projectId === projectId && comment.taskId === taskId);
  if (!taskExists) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  const newComment = { id: generateId(), projectId, taskId, content };
  commentsStore.push(newComment);
  return newComment;
}

module.exports = { getAllComments, addComment };
